def check(self) -> List[Tuple[EventType, str, str]]:
    """Returns list of (event_type, name, extra_info) tuples."""
    current = self.scan()
    events = []
    old_names = set(self._snapshot.keys())
    new_names = set(current.keys())
    created = new_names - old_names
    deleted = old_names - new_names
    # Detect renames: deleted file with same mtime as created file
    renamed_pairs = []
    for old_name in list(deleted):
        old_mtime = self._snapshot[old_name]
        for new_name in list(created):
            if current[new_name] == old_mtime:
                renamed_pairs.append((old_name, new_name))
                deleted.discard(old_name)
                created.discard(new_name)
                break
    for old_name, new_name in renamed_pairs:
        events.append((EventType.RENAMED, old_name, new_name))
    for name in created:
        events.append((EventType.CREATED, name, ''))
    for name in deleted:
        events.append((EventType.DELETED, name, ''))
    for name in old_names & new_names:
        if current[name] != self._snapshot[name]:
            events.append((EventType.MODIFIED, name, ''))
    self._snapshot = current
    return events
